import React, { useState, useEffect } from 'react';

export default function App() {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formatTime = (date) => {
    return date.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true,
    });
  };

  const formatDate = (date) => {
    return date.toLocaleDateString('en-US', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  };

  return (
    <div className="min-h-screen bg-neutral-950 text-neutral-100 flex flex-col font-sans">
      <main className="flex-grow flex flex-col items-center justify-center p-6">
        <div className="bg-neutral-900 border border-neutral-800 p-12 rounded-3xl shadow-2xl shadow-black/50 backdrop-blur-md text-center max-w-md w-full">
          <h1 className="text-neutral-400 text-sm uppercase tracking-widest mb-6 font-semibold">Current Time</h1>

          <div className="text-6xl font-bold text-white mb-2 font-mono tracking-tighter">
            {formatTime(time).split(' ')[0]}
          </div>
          <div className="text-xl text-blue-500 font-medium mb-8">
            {formatTime(time).split(' ')[1]}
          </div>

          <div className="h-px w-16 bg-neutral-800 mx-auto mb-8"></div>

          <div className="text-neutral-400 text-lg">
            {formatDate(time)}
          </div>
        </div>
      </main>

      <footer className="text-center p-4 text-neutral-400 text-xs opacity-80 flex justify-center items-center gap-1.5 mt-auto">
        <span>Built with</span>
        <img src="https://forge-app.vercel.app/logo.png" alt="Forge" className="w-3.5 h-3.5 rounded-sm object-cover" />
        <a href="https://forge-app.vercel.app" className="text-blue-500 font-semibold tracking-wide no-underline">FORGE</a>
      </footer>
    </div>
  );
}
